class SecurityValidator:
    @staticmethod
    def validate_input(data, max_size=1048576):
        if not data:
            raise ValueError("Input data cannot be empty")
        
        data_str = json.dumps(data) if isinstance(data, dict) else str(data)
        if len(data_str) > max_size:
            raise ValueError(f"Input exceeds maximum size of {max_size} bytes")
        
        return True
    
    @staticmethod
    def sanitize_string(value, max_length=1000):
        if not isinstance(value, str):
            return value
        
        sanitized = value[:max_length]
        dangerous_chars = ['<', '>', '"', "'", '&', '\x00']
        for char in dangerous_chars:
            sanitized = sanitized.replace(char, '')
        
        return sanitized
    
    @staticmethod
    def verify_hmac_signature(payload, signature, secret_key):
        expected_signature = hmac.new(
            secret_key.encode(),
            payload.encode(),
            hashlib.sha256
        ).hexdigest()
        
        return hmac.compare_digest(signature, expected_signature)
    
    @staticmethod
    def validate_timestamp(timestamp, max_age_seconds=300):
        current_time = int(time.time())
        if abs(current_time - timestamp) > max_age_seconds:
            raise ValueError("Request timestamp is too old or in the future")
        return True


class DynamoDBHelper:
    def __init__(self, table_name):
        self.dynamodb = boto3.resource('dynamodb')
        self.table = self.dynamodb.Table(table_name)
    
    def decimal_to_float(self, obj):
        if isinstance(obj, list):
            return [self.decimal_to_float(i) for i in obj]
        elif isinstance(obj, dict):
            return {k: self.decimal_to_float(v) for k, v in obj.items()}
        elif isinstance(obj, Decimal):
            return float(obj)
        return obj
    
    def put_item(self, item):
        try:
            response = self.table.put_item(Item=item)
            return response
        except ClientError as e:
            raise Exception(f"DynamoDB put_item failed: {e.response['Error']['Message']}")
    
    def get_item(self, key):
        try:
            response = self.table.get_item(Key=key)
            item = response.get('Item')
            return self.decimal_to_float(item) if item else None
        except ClientError as e:
            raise Exception(f"DynamoDB get_item failed: {e.response['Error']['Message']}")
    
    def query_items(self, key_condition_expression, **kwargs):
        try:
            response = self.table.query(
                KeyConditionExpression=key_condition_expression,
                **kwargs
            )
            items = response.get('Items', [])
            return self.decimal_to_float(items)
        except ClientError as e:
            raise Exception(f"DynamoDB query failed: {e.response['Error']['Message']}")


class S3Helper:
    def __init__(self, bucket_name):
        self.s3_client = boto3.client('s3')
        self.bucket_name = bucket_name
    
    def upload_object(self, key, data, encryption='aws:kms'):
        try:
            self.s3_client.put_object(
                Bucket=self.bucket_name,
                Key=key,
                Body=data,
                ServerSideEncryption=encryption
            )
        except ClientError as e:
            raise Exception(f"S3 upload failed: {e.response['Error']['Message']}")
    
    def download_object(self, key):
        try:
            response = self.s3_client.get_object(
                Bucket=self.bucket_name,
                Key=key
            )
            return response['Body'].read()
        except ClientError as e:
            raise Exception(f"S3 download failed: {e.response['Error']['Message']}")
    
    def delete_object(self, key):
        try:
            self.s3_client.delete_object(
                Bucket=self.bucket_name,
                Key=key
            )
        except ClientError as e:
            raise Exception(f"S3 delete failed: {e.response['Error']['Message']}")


class SNSHelper:
    def __init__(self, topic_arn):
        self.sns_client = boto3.client('sns')
        self.topic_arn = topic_arn
    
    def publish_message(self, message, subject=None, attributes=None):
        try:
            params = {
                'TopicArn': self.topic_arn,
                'Message': json.dumps(message) if isinstance(message, dict) else message
            }
            
            if subject:
                params['Subject'] = subject
            
            if attributes:
                params['MessageAttributes'] = attributes
            
            response = self.sns_client.publish(**params)
            return response['MessageId']
        except ClientError as e:
            raise Exception(f"SNS publish failed: {e.response['Error']['Message']}")


class SQSHelper:
    def __init__(self, queue_url):
        self.sqs_client = boto3.client('sqs')
        self.queue_url = queue_url
    
    def send_message(self, message, delay_seconds=0, attributes=None):
        try:
            params = {
                'QueueUrl': self.queue_url,
                'MessageBody': json.dumps(message) if isinstance(message, dict) else message,
                'DelaySeconds': delay_seconds
            }
            
            if attributes:
                params['MessageAttributes'] = attributes
            
            response = self.sqs_client.send_message(**params)
            return response['MessageId']
        except ClientError as e:
            raise Exception(f"SQS send_message failed: {e.response['Error']['Message']}")
    
    def receive_messages(self, max_messages=10, wait_time=0):
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=max_messages,
                WaitTimeSeconds=wait_time
            )
            return response.get('Messages', [])
        except ClientError as e:
            raise Exception(f"SQS receive_message failed: {e.response['Error']['Message']}")
    
    def delete_message(self, receipt_handle):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
        except ClientError as e:
            raise Exception(f"SQS delete_message failed: {e.response['Error']['Message']}")


def lambda_handler(event, context):
    validator = SecurityValidator()
    
    try:
        validator.validate_input(event)
        
        request_id = context.request_id
        function_name = context.function_name
        
        print(f"Processing request: {request_id} for function: {function_name}")
        
        event_type = event.get('eventType', 'unknown')
        payload = event.get('payload', {})
        
        if 'timestamp' in event:
            validator.validate_timestamp(event['timestamp'])
        
        if 'signature' in event and 'HMAC_SECRET_KEY' in os.environ:
            payload_str = json.dumps(payload, sort_keys=True)
            if not validator.verify_hmac_signature(
                payload_str,
                event['signature'],
                os.environ['HMAC_SECRET_KEY']
            ):
                raise ValueError("Invalid HMAC signature")
        
        table_name = os.environ.get('DYNAMODB_TABLE_NAME')
        bucket_name = os.environ.get('S3_BUCKET_NAME')
        topic_arn = os.environ.get('SNS_TOPIC_ARN')
        queue_url = os.environ.get('SQS_QUEUE_URL')
        
        result = {}
        
        if event_type == 'process_data':
            if table_name:
                db_helper = DynamoDBHelper(table_name)
                
                item_id = payload.get('id')
                data = payload.get('data', {})
                
                sanitized_data = {
                    k: validator.sanitize_string(v) if isinstance(v, str) else v
                    for k, v in data.items()
                }
                
                db_item = {
                    'id': item_id,
                    'data': sanitized_data,
                    'timestamp': int(time.time()),
                    'processed_by': function_name
                }
                
                db_helper.put_item(db_item)
                result['database'] = 'Item stored successfully'
            
            if bucket_name:
                s3_helper = S3Helper(bucket_name)
                
                file_key = f"processed/{item_id}_{int(time.time())}.json"
                s3_helper.upload_object(
                    file_key,
                    json.dumps(sanitized_data),
                    encryption='aws:kms'
                )
                result['storage'] = f'File uploaded to {file_key}'
            
            if topic_arn:
                sns_helper = SNSHelper(topic_arn)
                
                notification = {
                    'event': 'data_processed',
                    'id': item_id,
                    'timestamp': datetime.utcnow().isoformat(),
                    'function': function_name
                }
                
                message_id = sns_helper.publish_message(
                    notification,
                    subject='Data Processing Complete'
                )
                result['notification'] = f'SNS message published: {message_id}'
            
            if queue_url:
                sqs_helper = SQSHelper(queue_url)
                
                queue_message = {
                    'action': 'post_process',
                    'id': item_id,
                    'timestamp': int(time.time())
                }
                
                message_id = sqs_helper.send_message(queue_message)
                result['queue'] = f'SQS message sent: {message_id}'
        
        elif event_type == 'retrieve_data':
            if table_name:
                db_helper = DynamoDBHelper(table_name)
                
                item_id = payload.get('id')
                item = db_helper.get_item({'id': item_id})
                result['item'] = item
        
        elif event_type == 'sqs_processor':
            if 'Records' in event:
                sqs_helper = SQSHelper(queue_url) if queue_url else None
                
                for record in event['Records']:
                    message_body = json.loads(record['body'])
                    
                    print(f"Processing SQS message: {message_body}")
                    
                    if sqs_helper:
                        sqs_helper.delete_message(record['receiptHandle'])
                
                result['processed_messages'] = len(event['Records'])
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'X-Request-ID': request_id,
                'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
                'X-Content-Type-Options': 'nosniff',
                'X-Frame-Options': 'DENY'
            },
            'body': json.dumps({
                'success': True,
                'requestId': request_id,
                'result': result,
                'timestamp': datetime.utcnow().isoformat()
            })
        }
    
    except ValueError as e:
        print(f"Validation error: {str(e)}")
        return {
            'statusCode': 400,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({
                'success': False,
                'error': 'Validation error',
                'message': str(e)
            })
        }
    
    except Exception as e:
        print(f"Error processing request: {str(e)}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({
                'success': False,
                'error': 'Internal server error',
                'requestId': context.request_id
            })
        }